                     CourseID = courses.Single(c => c.Title == "Composition").CourseID,
                     Grade = Grade.B
                 },
                 new Enrollment {
                     StudentID = students.Single(s => s.LastName == "Justice").ID,
                     CourseID = courses.Single(c => c.Title == "Literature").CourseID,
                     Grade = Grade.B
                 }
             };

             foreach (Enrollment e in enrollments)
