    public class PersonTests
    {
        private class ConcretePerson : Person { }

        [Fact]
        public void FullName_ReturnsLastNameCommaFirstName()
        {
            var person = new ConcretePerson { LastName = "Smith", FirstMidName = "John" };
            Assert.Equal("Smith, John", person.FullName);
        }

        [Fact]
        public void FullName_HandlesEmptyNames()
        {
            var person = new ConcretePerson { LastName = "", FirstMidName = "" };
            Assert.Equal(", ", person.FullName);
        }

        [Fact]
        public void ID_DefaultsToZero()
        {
            var person = new ConcretePerson();
            Assert.Equal(0, person.ID);
        }

        [Fact]
        public void LastName_HasRequiredAttribute()
        {
            var prop = typeof(Person).GetProperty(nameof(Person.LastName));
            Assert.NotNull(prop.GetCustomAttribute<RequiredAttribute>());
        }

        [Fact]
        public void LastName_HasStringLengthAttribute_Max50()
        {
            var prop = typeof(Person).GetProperty(nameof(Person.LastName));
            var attr = prop.GetCustomAttribute<StringLengthAttribute>();
            Assert.NotNull(attr);
            Assert.Equal(50, attr.MaximumLength);
        }

        [Fact]
        public void FirstMidName_HasRequiredAttribute()
        {
            var prop = typeof(Person).GetProperty(nameof(Person.FirstMidName));
            Assert.NotNull(prop.GetCustomAttribute<RequiredAttribute>());
        }

        [Fact]
        public void FirstMidName_HasStringLengthAttribute_Max50()
        {
            var prop = typeof(Person).GetProperty(nameof(Person.FirstMidName));
            var attr = prop.GetCustomAttribute<StringLengthAttribute>();
            Assert.NotNull(attr);
            Assert.Equal(50, attr.MaximumLength);
        }

        [Fact]
        public void Validation_FailsWhenLastNameMissing()
        {
            var person = new ConcretePerson { FirstMidName = "John" };
            var context = new ValidationContext(person);
            var results = new List<ValidationResult>();
            Assert.False(Validator.TryValidateProperty(person.LastName, new ValidationContext(person) { MemberName = "LastName" }, results));
        }

        [Fact]
        public void Validation_FailsWhenFirstMidNameMissing()
        {
            var person = new ConcretePerson { LastName = "Smith" };
            var context = new ValidationContext(person);
            var results = new List<ValidationResult>();
            Assert.False(Validator.TryValidateProperty(person.FirstMidName, new ValidationContext(person) { MemberName = "FirstMidName" }, results));
        }
