using System;
using System.Collections.Generic;
using System.ComponentModel.DataAnnotations;
using Xunit;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests.Models
{
    public class PersonTests
    {
        private class ConcretePerson : Person { }

        [Fact]
        public void FullName_ReturnsLastNameCommaFirstName()
        {
            var person = new ConcretePerson { LastName = "Smith", FirstMidName = "John" };
            Assert.Equal("Smith, John", person.FullName);
        }

        [Fact]
        public void FullName_HandlesEmptyNames()
        {
            var person = new ConcretePerson { LastName = "", FirstMidName = "" };
            Assert.Equal(", ", person.FullName);
        }

        [Fact]
        public void ID_DefaultsToZero()
        {
            var person = new ConcretePerson();
            Assert.Equal(0, person.ID);
        }

        [Fact]
        public void LastName_HasRequiredAttribute()
        {
            var prop = typeof(Person).GetProperty(nameof(Person.LastName));
            Assert.NotNull(prop!.GetCustomAttribute<RequiredAttribute>());
        }

        [Fact]
        public void LastName_HasStringLengthAttribute_Max50()
        {
            var prop = typeof(Person).GetProperty(nameof(Person.LastName));
            var attr = prop!.GetCustomAttribute<StringLengthAttribute>();
            Assert.NotNull(attr);
            Assert.Equal(50, attr!.MaximumLength);
        }

        [Fact]
        public void FirstMidName_HasRequiredAttribute()
        {
            var prop = typeof(Person).GetProperty(nameof(Person.FirstMidName));
            Assert.NotNull(prop!.GetCustomAttribute<RequiredAttribute>());
        }

        [Fact]
        public void FirstMidName_HasStringLengthAttribute_Max50()
        {
            var prop = typeof(Person).GetProperty(nameof(Person.FirstMidName));
            var attr = prop!.GetCustomAttribute<StringLengthAttribute>();
            Assert.NotNull(attr);
            Assert.Equal(50, attr!.MaximumLength);
        }

        [Fact]
        public void Validation_FailsWhenLastNameMissing()
        {
            var person = new ConcretePerson { FirstMidName = "John" };
            var results = new List<ValidationResult>();
            Assert.False(Validator.TryValidateProperty(person.LastName, new ValidationContext(person) { MemberName = "LastName" }, results));
        }

        [Fact]
        public void Validation_FailsWhenFirstMidNameMissing()
        {
            var person = new ConcretePerson { LastName = "Smith" };
            var results = new List<ValidationResult>();
            Assert.False(Validator.TryValidateProperty(person.FirstMidName, new ValidationContext(person) { MemberName = "FirstMidName" }, results));
        }
    }

    public class StudentTests
    {
        [Fact]
        public void Student_InheritsFromPerson()
        {
            Assert.True(typeof(Person).IsAssignableFrom(typeof(Student)));
        }

        [Fact]
        public void Student_HasEnrollmentDateProperty()
        {
            var student = new Student { EnrollmentDate = new DateTime(2023, 9, 1) };
            Assert.Equal(new DateTime(2023, 9, 1), student.EnrollmentDate);
        }

        [Fact]
        public void Student_HasEnrollmentsCollection()
        {
            var student = new Student { Enrollments = new List<Enrollment>() };
            Assert.NotNull(student.Enrollments);
            Assert.Empty(student.Enrollments);
        }

        [Fact]
        public void Student_FullNameWorks()
        {
            var student = new Student { LastName = "Doe", FirstMidName = "Jane" };
            Assert.Equal("Doe, Jane", student.FullName);
        }

        [Fact]
        public void EnrollmentDate_HasRequiredAttribute()
        {
            var prop = typeof(Student).GetProperty(nameof(Student.EnrollmentDate));
            Assert.NotNull(prop!.GetCustomAttribute<RequiredAttribute>());
        }
    }

    public class InstructorTests
    {
        [Fact]
        public void Instructor_InheritsFromPerson()
        {
            Assert.True(typeof(Person).IsAssignableFrom(typeof(Instructor)));
        }

        [Fact]
        public void Instructor_HasHireDateProperty()
        {
            var instructor = new Instructor { HireDate = new DateTime(2000, 1, 15) };
            Assert.Equal(new DateTime(2000, 1, 15), instructor.HireDate);
        }

        [Fact]
        public void Instructor_HasCourseAssignmentsCollection()
        {
            var instructor = new Instructor { CourseAssignments = new List<CourseAssignment>() };
            Assert.NotNull(instructor.CourseAssignments);
        }

        [Fact]
        public void Instructor_HasOfficeAssignment()
        {
            var office = new OfficeAssignment { Location = "Room 101" };
            var instructor = new Instructor { OfficeAssignment = office };
            Assert.Equal("Room 101", instructor.OfficeAssignment.Location);
        }

        [Fact]
        public void HireDate_HasRequiredAttribute()
        {
            var prop = typeof(Instructor).GetProperty(nameof(Instructor.HireDate));
            Assert.NotNull(prop!.GetCustomAttribute<RequiredAttribute>());
        }
    }

    public class CourseTests
    {
        [Fact]
        public void Course_PropertiesSetCorrectly()
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1
            };

            Assert.Equal(1050, course.CourseID);
            Assert.Equal("Chemistry", course.Title);
            Assert.Equal(3, course.Credits);
            Assert.Equal(1, course.DepartmentID);
        }

        [Fact]
        public void Course_HasNavigationProperties()
        {
            var course = new Course
            {
                Department = new Department { Name = "Science" },
                Enrollments = new List<Enrollment>(),
                CourseAssignments = new List<CourseAssignment>()
            };

            Assert.NotNull(course.Department);
            Assert.NotNull(course.Enrollments);
            Assert.NotNull(course.CourseAssignments);
        }

        [Fact]
        public void Title_HasStringLengthAttribute()
        {
            var prop = typeof(Course).GetProperty(nameof(Course.Title));
            var attr = prop!.GetCustomAttribute<StringLengthAttribute>();
            Assert.NotNull(attr);
            Assert.Equal(50, attr!.MaximumLength);
            Assert.Equal(3, attr.MinimumLength);
        }

        [Fact]
        public void Credits_HasRangeAttribute()
        {
            var prop = typeof(Course).GetProperty(nameof(Course.Credits));
            var attr = prop!.GetCustomAttribute<RangeAttribute>();
            Assert.NotNull(attr);
            Assert.Equal(0, attr!.Minimum);
            Assert.Equal(5, attr.Maximum);
        }

        [Fact]
        public void TeachingMaterialImagePath_HasStringLengthAttribute()
        {
            var prop = typeof(Course).GetProperty(nameof(Course.TeachingMaterialImagePath));
            var attr = prop!.GetCustomAttribute<StringLengthAttribute>();
            Assert.NotNull(attr);
            Assert.Equal(255, attr!.MaximumLength);
        }

        [Theory]
        [InlineData(-1)]
        [InlineData(6)]
        public void Credits_ValidationFailsForOutOfRange(int credits)
        {
            var course = new Course { CourseID = 1, Title = "Test", Credits = credits, DepartmentID = 1 };
            var results = new List<ValidationResult>();
            Assert.False(Validator.TryValidateProperty(
                course.Credits,
                new ValidationContext(course) { MemberName = "Credits" },
                results));
        }

        [Theory]
        [InlineData(0)]
        [InlineData(3)]
        [InlineData(5)]
        public void Credits_ValidationSucceedsForValidRange(int credits)
        {
            var course = new Course { CourseID = 1, Title = "Test", Credits = credits, DepartmentID = 1 };
            var results = new List<ValidationResult>();
            Assert.True(Validator.TryValidateProperty(
                course.Credits,
                new ValidationContext(course) { MemberName = "Credits" },
                results));
        }
    }

    public class DepartmentTests
    {
        [Fact]
        public void Department_PropertiesSetCorrectly()
        {
            var dept = new Department
            {
                DepartmentID = 1,
                Name = "Engineering",
                Budget = 350000m,
                StartDate = new DateTime(2007, 9, 1),
                InstructorID = 5
            };

