using System.Collections.Generic;

namespace ContosoUniversity.Tests.Models
{
    public class SchoolViewModelTests
    {
        [Fact]
        public void AssignedCourseData_PropertiesSetCorrectly()
        {
            var data = new AssignedCourseData
            {
                CourseID = 1050,
                Title = "Chemistry",
                Assigned = true
            };

            Assert.Equal(1050, data.CourseID);
            Assert.Equal("Chemistry", data.Title);
            Assert.True(data.Assigned);
        }

        [Fact]
        public void AssignedCourseData_DefaultAssignedIsFalse()
        {
            var data = new AssignedCourseData();
            Assert.False(data.Assigned);
        }

        [Fact]
        public void EnrollmentDateGroup_PropertiesSetCorrectly()
        {
            var date = new DateTime(2023, 9, 1);
            var group = new EnrollmentDateGroup
            {
                EnrollmentDate = date,
                StudentCount = 5
            };

            Assert.Equal(date, group.EnrollmentDate);
            Assert.Equal(5, group.StudentCount);
        }

        [Fact]
        public void EnrollmentDateGroup_EnrollmentDateCanBeNull()
        {
            var group = new EnrollmentDateGroup { EnrollmentDate = null };
            Assert.Null(group.EnrollmentDate);
        }

        [Fact]
        public void InstructorIndexData_PropertiesSetCorrectly()
        {
            var data = new InstructorIndexData
            {
                Instructors = new List<Instructor>(),
                Courses = new List<Course>(),
                Enrollments = new List<Enrollment>()
            };

            Assert.NotNull(data.Instructors);
            Assert.NotNull(data.Courses);
            Assert.NotNull(data.Enrollments);
        }

        [Fact]
        public void InstructorIndexData_DefaultsAreNull()
        {
            var data = new InstructorIndexData();
            Assert.Null(data.Instructors);
            Assert.Null(data.Courses);
            Assert.Null(data.Enrollments);
        }
    }
}

